import { describe, expect, it } from 'vitest';
import { buildTutoringAct } from '../../src/tutor/acts';

describe('buildTutoringAct', () => {
  it('builds a scoped tutoring act from lesson state only', () => {
    const act = buildTutoringAct({
      session: { sessionId: 'sess-1', childId: 'child-1', guardianId: 'guardian-1', lessonId: 'lesson-1', mode: 'child', startedBy: 'guardian', status: 'active' },
      playback: { state: 'presenting', lessonId: 'lesson-1', cursor: 2 },
      projection: { childId: 'child-1', strengths: ['counting'] }
    });
    expect(act.lessonId).toBe('lesson-1');
    expect(act.childId).toBe('child-1');
  });

  it('rejects cross-child projection data', () => {
    expect(() => buildTutoringAct({
      session: { sessionId: 'sess-1', childId: 'child-1', guardianId: 'guardian-1', lessonId: 'lesson-1', mode: 'child', startedBy: 'guardian', status: 'active' },
      playback: { state: 'presenting', lessonId: 'lesson-1', cursor: 2 },
      projection: { childId: 'child-2' }
    } as any)).toThrow(/child/i);
  });
});

