import type { SessionEnvelope } from './session_envelope';
import type { LessonPlaybackSnapshot } from './lesson_playback';

export type TutoringActKind = 'explain' | 'ask_check' | 'encourage' | 'clarify_next_step';

export interface TutoringAct {
  kind: TutoringActKind;
  childId: string;
  lessonId: string;
  prompt: string;
}

export function buildTutoringAct(input: {
  session: SessionEnvelope;
  playback: LessonPlaybackSnapshot;
  projection: { childId: string; [key: string]: unknown };
}): TutoringAct {
  return {
    kind: 'explain',
    childId: input.session.childId,
    lessonId: input.session.lessonId,
    prompt: ''
  };
}
